@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Load initial notifications during SSR — these render into the HTML immediately.
        _notifications = NotificationService.GetNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is interactive in the browser,
            // so the polling loop will never run during the static SSR pass.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        // Track the highest ID we already have so we only fetch new ones.
        var lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

            var newItems = NotificationService.GetNotificationsSince(lastId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                lastId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

